from flask import Flask, request, jsonify
from pymemcache.client.base import Client
from pymemcache.client.retrying import RetryingClient
from pymemcache.exceptions import MemcacheUnexpectedCloseError


app = Flask(__name__)

# Configuration
app.config['MEMCACHED_HOST'] = 'localhost'
app.config['MEMCACHED_PORT'] = 11211
app.config['DEFAULT_CACHE_TTL'] = 300  # 5 minutes
app.config['API_CACHE_TTL'] = 60  # 1 minute
app.config['DB_CACHE_TTL'] = 600  # 10 minutes


# JSON serializer/deserializer for Memcached
def json_serializer(key, value):
    if isinstance(value, str):
        return value.encode('utf-8'), 1
    return json.dumps(value).encode('utf-8'), 2


def json_deserializer(key, value, flags):
    if flags == 1:
        return value.decode('utf-8')
    if flags == 2:
        return json.loads(value.decode('utf-8'))
    raise ValueError(f"Unknown serialization format flag: {flags}")


# Initialize Memcached client with retry logic
def get_memcached_client():
    base_client = Client(
        (app.config['MEMCACHED_HOST'], app.config['MEMCACHED_PORT']),
        serializer=json_serializer,
        deserializer=json_deserializer,
        connect_timeout=5,
        timeout=3,
        no_delay=True,
    )
    client = RetryingClient(
        base_client,
        attempts=3,
        retry_delay=0.1,
        retry_for=[MemcacheUnexpectedCloseError, ConnectionRefusedError, OSError],
    )
    return client


cache_client = get_memcached_client()


# --- Cache Helper Functions ---

def generate_cache_key(prefix, *args, **kwargs):
    """Generate a consistent cache key from prefix and arguments."""
    key_data = f"{prefix}:{json.dumps(args, sort_keys=True)}:{json.dumps(kwargs, sort_keys=True)}"
    key_hash = hashlib.md5(key_data.encode('utf-8')).hexdigest()
    return f"{prefix}:{key_hash}"


def cache_get(key):
    """Get a value from cache, return None if not found or on error."""
    try:
        result = cache_client.get(key)
        if result is not None:
            app.logger.debug(f"Cache HIT for key: {key}")
        else:
            app.logger.debug(f"Cache MISS for key: {key}")
        return result
    except Exception as e:
        app.logger.error(f"Cache GET error for key {key}: {e}")
        return None


def cache_set(key, value, ttl=None):
    """Set a value in cache with optional TTL."""
    if ttl is None:
        ttl = app.config['DEFAULT_CACHE_TTL']
    try:
        cache_client.set(key, value, expire=ttl)
        app.logger.debug(f"Cache SET for key: {key} with TTL: {ttl}")
        return True
    except Exception as e:
        app.logger.error(f"Cache SET error for key {key}: {e}")
        return False


def cache_delete(key):
    """Delete a value from cache."""
    try:
        cache_client.delete(key)
        app.logger.debug(f"Cache DELETE for key: {key}")
        return True
    except Exception as e:
        app.logger.error(f"Cache DELETE error for key {key}: {e}")
        return False


def cache_flush():
    """Flush all cache entries."""
    try:
        cache_client.flush_all()
        app.logger.info("Cache FLUSH ALL")
        return True
    except Exception as e:
        app.logger.error(f"Cache FLUSH ALL error: {e}")
        return False


# --- Decorators ---

def cached_route(ttl=None, key_prefix=None):
    """Decorator to cache Flask route responses."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            prefix = key_prefix or f"route:{request.path}"
            # Include query parameters in cache key
            query_string = request.query_string.decode('utf-8')
            cache_key = generate_cache_key(prefix, query_string, **kwargs)

            # Try to get from cache
            cached_result = cache_get(cache_key)
            if cached_result is not None:
                response = cached_result.copy()
                response['_cache'] = 'HIT'
                return jsonify(response)

            # Execute the function
            result = f(*args, **kwargs)

            # If result is a dict, cache it
            if isinstance(result, dict):
                cache_ttl = ttl or app.config['API_CACHE_TTL']
                cache_set(cache_key, result, ttl=cache_ttl)
                result['_cache'] = 'MISS'
                return jsonify(result)

            return result
        return decorated_function
    return decorator


def cached_function(ttl=None, key_prefix=None):
    """Decorator to cache any function's return value (e.g., DB queries)."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            prefix = key_prefix or f"func:{f.__module__}.{f.__name__}"
            cache_key = generate_cache_key(prefix, *args, **kwargs)

            # Try to get from cache
            cached_result = cache_get(cache_key)
            if cached_result is not None:
                return cached_result

            # Execute the function
            result = f(*args, **kwargs)

            # Cache the result
            cache_ttl = ttl or app.config['DEFAULT_CACHE_TTL']
            cache_set(cache_key, result, ttl=cache_ttl)

            return result
        return decorated_function
    return decorator


